class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int changes = 0;
        for (int i = 0; i < n; i += k) {
            int end = Math.min(i + k, n);
            String substring = s.substring(i, end);
            int localChanges = 0;
            for (int j = 0, l = substring.length() - 1; j < l; j++, l--) {
                if (substring.charAt(j) != substring.charAt(l)) {
                    localChanges++;
                }
            }
            changes += localChanges;
        }
        return changes;
    }
}
